const THEME_STORAGE_KEY = 'edb-theme';

const getSystemPreference = () => {
  if (typeof window === 'undefined') return 'light';
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
};

const getInitialTheme = () => {
  if (typeof window === 'undefined') return 'light';
  if (typeof window.__INITIAL_THEME__ === 'string') return window.__INITIAL_THEME__;
  try {
    const stored = window.localStorage.getItem(THEME_STORAGE_KEY);
    if (stored === 'light' || stored === 'dark') return stored;
  } catch (e) {}
  return getSystemPreference();
};

function BlogContactPopup({ isOpen, onClose }) {
  useEffect(() => {
    if (typeof document === 'undefined') return;
    if (isOpen) {
      document.documentElement.style.overflow = 'hidden';
    } else {
      document.documentElement.style.overflow = '';
    }
    return () => { document.documentElement.style.overflow = ''; };
  }, [isOpen]);

  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70" onClick={onClose}>
      <div
        className="bg-white dark:bg-slate-800 rounded-2xl shadow-2xl max-w-md w-full p-8 text-center"
        onClick={(e) => e.stopPropagation()}
      >
        <button onClick={onClose} className="absolute top-4 right-4 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200"><X size={20} /></button>
        <div className="w-14 h-14 bg-gradient-to-br from-sky-500 to-blue-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
          <Mail className="w-7 h-7 text-white" />
        </div>
        <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Email Support</h3>
        <p className="text-slate-600 dark:text-slate-300 mb-4 text-sm">Questions, feature requests or issues? Contact us directly. We personally read and respond to all messages.</p>
        <a href="mailto:contact@qod.ee" className="text-sky-600 dark:text-sky-400 font-semibold hover:underline">contact@qod.ee</a>
      </div>
    </div>
  );
}

