export default function BlogLayout({ title, description, date, readTime = '4 min read', isIndex = false, children }) {
  const [theme, setTheme] = useState(getInitialTheme);
  const [hasManualPreference, setHasManualPreference] = useState(() => {
    if (typeof window === 'undefined') return false;
    try {
      const stored = window.localStorage.getItem(THEME_STORAGE_KEY);
      return stored === 'light' || stored === 'dark';
    } catch { return false; }
  });
  const [showContact, setShowContact] = useState(false);
  const [showPrivacy, setShowPrivacy] = useState(false);

  useEffect(() => {
    if (typeof document === 'undefined') return;
    document.documentElement.classList.toggle('dark', theme === 'dark');
    document.documentElement.dataset.theme = theme;
    document.documentElement.style.colorScheme = theme;
    if (typeof window !== 'undefined') window.__INITIAL_THEME__ = theme;
  }, [theme]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    const mq = window.matchMedia('(prefers-color-scheme: dark)');
    const sync = (e) => { if (!hasManualPreference) setTheme(e.matches ? 'dark' : 'light'); };
    if (!hasManualPreference) setTheme(mq.matches ? 'dark' : 'light');
    mq.addEventListener('change', sync);
    return () => mq.removeEventListener('change', sync);
  }, [hasManualPreference]);

  const handleToggleTheme = useCallback((event) => {
    const apply = () => {
      flushSync(() => {
        setTheme((cur) => {
          const next = cur === 'dark' ? 'light' : 'dark';
          setHasManualPreference(true);
          try { window.localStorage.setItem(THEME_STORAGE_KEY, next); } catch {}
          return next;
        });
      });
    };
    if (!document.startViewTransition || !event) { apply(); return; }
    const { clientX: x, clientY: y } = event;
    const r = Math.hypot(Math.max(x, innerWidth - x), Math.max(y, innerHeight - y));
    document.startViewTransition(apply).ready.then(() => {
      document.documentElement.animate(
        { clipPath: [`circle(0px at ${x}px ${y}px)`, `circle(${r}px at ${x}px ${y}px)`] },
        { duration: 500, easing: 'ease-in-out', pseudoElement: '::view-transition-new(root)' }
      );
    });
  }, []);

  useEffect(() => {
    if (typeof document === 'undefined') return;
    document.title = title + ' | External Display Browser';
    const setMeta = (sel, val) => {
      const el = document.querySelector(sel);
      if (el) el.setAttribute('content', val);
    };
    setMeta('meta[name="description"]', description);
    setMeta('meta[property="og:title"]', title);
    setMeta('meta[property="og:description"]', description);
  }, [title, description]);

  // Open contact/privacy popup from path if navigated directly
  useEffect(() => {
    const path = window.location.pathname;
    if (path.endsWith('/contact')) setShowContact(true);
    else if (path.endsWith('/privacy')) setShowPrivacy(true);
  }, []);

  return (
    <div className="min-h-screen bg-white dark:bg-slate-900">
      <Header theme={theme} onToggleTheme={handleToggleTheme} />

      <main className="pt-16">
        {/* Breadcrumb */}
        <div className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700">
          <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-3">
            <nav className="flex items-center gap-2 text-sm text-slate-500 dark:text-slate-400 flex-wrap">
              <a href="/" className="hover:text-sky-600 dark:hover:text-sky-400 transition-colors">Home</a>
              <span>/</span>
              <Link to="/blog" className="hover:text-sky-600 dark:hover:text-sky-400 transition-colors">Blog</Link>
              <span>/</span>
              <span className="text-slate-700 dark:text-slate-300 truncate">{title}</span>
            </nav>
          </div>
        </div>

        {/* Article */}
        <article className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8 py-10 sm:py-14">
          {/* Article header */}
          <header className="mb-10">
            <div className="flex items-center gap-3 mb-4 flex-wrap">
              <span className="inline-flex items-center gap-1.5 px-3 py-1 bg-sky-100 dark:bg-sky-900/40 text-sky-700 dark:text-sky-300 rounded-full text-xs font-semibold">
                <img src={monitorIconUrl} alt="" className="w-3.5 h-3.5 rounded" />
                External Display Browser
              </span>
              {date && (
                <span className="flex items-center gap-1 text-xs text-slate-500 dark:text-slate-400">
                  <Calendar className="w-3.5 h-3.5" />
                  {date}
                </span>
              )}
              {readTime && (
                <span className="flex items-center gap-1 text-xs text-slate-500 dark:text-slate-400">
                  <Clock className="w-3.5 h-3.5" />
                  {readTime}
                </span>
              )}
            </div>
            <h1 className="text-3xl sm:text-4xl font-bold text-slate-900 dark:text-white leading-tight mb-4">{title}</h1>
            <p className="text-lg text-slate-600 dark:text-slate-300 leading-relaxed">{description}</p>
          </header>

          {/* Content */}
          <div className="prose-custom">
            {children}
          </div>

          {/* Big CTA */}
          <div className="mt-14 bg-gradient-to-br from-sky-500 via-blue-600 to-indigo-600 rounded-2xl p-8 text-center text-white shadow-xl">
            <img src={monitorIconUrl} alt="External Display Browser" className="w-14 h-14 rounded-2xl shadow-lg mx-auto mb-4" />
            <h3 className="text-2xl font-bold mb-2">Try External Display Browser</h3>
            <p className="text-blue-100 mb-6 max-w-md mx-auto text-sm leading-relaxed">Full screen on any external monitor, TV or portable display. No black bars. Download on the App Store.</p>
            <AppStoreBadges />
          </div>

          {/* Back */}
          <div className="mt-10 pt-8 border-t border-slate-200 dark:border-slate-700 flex items-center justify-between flex-wrap gap-4">
            {isIndex ? (
              <a href="/" className="inline-flex items-center gap-2 text-sky-600 dark:text-sky-400 hover:underline text-sm font-medium">
                <ArrowLeft className="w-4 h-4" />
                Back to home
              </a>
            ) : (
              <Link to="/blog" className="inline-flex items-center gap-2 text-sky-600 dark:text-sky-400 hover:underline text-sm font-medium">
                <ArrowLeft className="w-4 h-4" />
                All articles
              </Link>
            )}
            <a
              href="https://apps.apple.com/us/app/external-display-browser/id6758286241"
              target="_blank"
              rel="noopener noreferrer"
              className="text-sm text-slate-500 dark:text-slate-400 hover:text-sky-600 dark:hover:text-sky-400 transition-colors"
            >
              Download on App Store
            </a>
          </div>
        </article>
      </main>

      <Footer
        openContactPopup={() => setShowContact(true)}
        openPrivacyPopup={() => setShowPrivacy(true)}
      />
      <BlogContactPopup isOpen={showContact} onClose={() => setShowContact(false)} />
    </div>
  );
}
